import{_ as n,c as a,a as i,o as e}from"./app-CEcM0piI.js";const l={};function t(p,s){return e(),a("div",null,s[0]||(s[0]=[i(`<p>C++ 异常处理涉及到三个关键字：<strong>try、catch、throw、noexcept</strong>。</p><ul><li><code>try</code>：识别异常</li><li><code>catch</code>：捕获异常。</li><li><code>throw</code>：抛出异常</li><li><code>noexcept</code>：用于声明函数不抛出异常，如果函数抛了异常，则直接中断，不能被捕获</li></ul><p>try……catch语法：</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>try</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>   // 保护代码</span></span>
<span class="line"><span>}catch( ExceptionName e1 )</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>   // catch 块</span></span>
<span class="line"><span>}catch( ExceptionName e2 )</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>   // catch 块</span></span>
<span class="line"><span>}catch( ExceptionName eN )</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>   // catch 块</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>throw 语法：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>throw 表达式;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>执行过程</p><ul><li>执行 try 块中的语句，如果执行的过程中没有异常拋出，那么执行完后就跳出语句，所有 catch 块中的语句都不会被执行；</li><li>如果 try 块执行的过程中拋出了异常，那么拋出异常后立即跳转到第一个“异常类型”和拋出的异常类型匹配的 catch 块中执行（称作异常被该 catch 块“捕获”），执行完后再跳转到最后一个 catch 块后面继续执行。</li><li>如果抛出的异常一直没有函数捕获(catch)，则会一直上传到c++运行系统那里，导致整个程序的终止。</li></ul><p><strong>捕获异常时的注意事项：</strong></p><ol><li>catch的匹配过程是找<strong>最先匹配</strong>的，不是最佳匹配。</li><li>catch的匹配过程中，对类型的要求比较<strong>严格</strong>。<strong>不</strong>允许<strong>标准算术转换</strong>和<strong>类类型的转换</strong>。（类类型的转化包括<strong>两</strong>种：通过构造函数的<strong>隐式类型转化</strong>和通过<strong>转化操作符</strong>的类型转化）。</li></ol><p>异常被抛出后，从进入try块起，到异常被抛掷前，这期间在栈上构造的所有对象，都会被自动析构。 析构的顺序与构造的顺序相反，这一过程称为栈的解旋(unwinding).</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>struct Maker {  </span></span>
<span class="line"><span>    Maker() {cout &lt;&lt; &quot;Maker() 构造函数&quot; &lt;&lt; endl;}  </span></span>
<span class="line"><span>    Maker(const Maker &amp;other) {cout &lt;&lt; &quot;Maker(Maker&amp;) 拷贝构造函数&quot; &lt;&lt; endl;}  </span></span>
<span class="line"><span>    ~Maker() {cout &lt;&lt; &quot;~Maker() 析构函数&quot; &lt;&lt; endl;}  </span></span>
<span class="line"><span>};  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>void fun() {  </span></span>
<span class="line"><span>    Maker m;  </span></span>
<span class="line"><span>    cout &lt;&lt; &quot;--------&quot; &lt;&lt; endl;  </span></span>
<span class="line"><span>    throw m;  </span></span>
<span class="line"><span>    cout &lt;&lt; &quot;fun__end&quot; &lt;&lt; endl;  </span></span>
<span class="line"><span>}  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>int main() {  </span></span>
<span class="line"><span>    try {  </span></span>
<span class="line"><span>        fun();  </span></span>
<span class="line"><span>    }  </span></span>
<span class="line"><span>    catch (Maker &amp;m) {  </span></span>
<span class="line"><span>        cout &lt;&lt; &quot;收到Maker异常&quot; &lt;&lt; endl;  </span></span>
<span class="line"><span>    }  </span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h3 id="throw用在函数头和函数体之间" tabindex="-1"><a class="header-anchor" href="#throw用在函数头和函数体之间"><span>throw用在函数头和函数体之间</span></a></h3><p>throw 关键字除了可以用在函数体中抛出异常，还可以用在函数头和函数体之间，指明当前函数能够抛出的异常类型，这称为异常规范（Exception specification）也称为异常指示符或异常列表</p><p>使用函数异常声明列表来查看函数可能抛出的异常</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void func() throw (int,double);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>该声明指出 func 可能抛出int和 double 类型的异常。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void func() throw();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>表示函数 func 不抛出任何异常，而这种写法在 c++11 中被新的关键字 noexcept 异常声明所取代。</p>`,19)]))}const d=n(l,[["render",t]]),r=JSON.parse('{"path":"/cpp/cpp/9/","title":"9、异常处理","lang":"zh-CN","frontmatter":{"title":"9、异常处理","createTime":"2025/06/22 11:11:16","permalink":"/cpp/cpp/9/"},"readingTime":{"minutes":2.22,"words":666},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/C++/9、异常处理.md","headers":[]}');export{d as comp,r as data};
